function renderEnvironmentRegistryPage(){const environments=coerceList((state.admin||{}).environments);const statusById={};coerceList((state.appShell||{}).environments).forEach(function(environment){statusById[environment.id]=environment;});const healthy=environments.filter(function(environment){return(statusById[environment.id]||{}).status==="healthy";}).length;const warning=environments.filter(function(environment){return(statusById[environment.id]||{}).status==="warning";}).length;const down=environments.filter(function(environment){return(statusById[environment.id]||{}).status==="down";}).length;return`<div class="content-stack">${renderSummaryTiles([{label:"Registered Environments",value:environments.length,copy:"Saved IAM environments available from the header context switcher."},{label:"Healthy",value:healthy,copy:"Environments returning healthy status."},{label:"Warning",value:warning,copy:"Environments with partial degradation."},{label:"Down",value:down,copy:"Environments currently unreachable or failing."}])}<section class="panel"><div class="panel-header"><div><h3 class="panel-title">Environment Registry</h3><p class="panel-copy">Add environments here. Switch between them from the top-right context selector.</p></div><div class="panel-actions"><button class="button is-primary" type="button" data-create-environment>Create Environment</button></div></div>${environments.length===0?renderEmptyPanel("No environments yet","Create the first Oracle IAM environment to start using the dashboard."):`<div class="table-wrap"><table><thead><tr><th>Environment</th><th>Type</th><th>Host</th><th>Products</th><th>Status</th><th>Last Collection</th><th>Actions</th></tr></thead><tbody>${environments.map(function(environment){const overview=statusById[environment.id]||{};return`<tr><td><div class="strong">${escapeHtml(environment.name||"-")}</div><div class="table-label">${escapeHtml(environment.description||"")}</div></td><td>${escapeHtml(uppercaseType(environment.environmentType))}</td><td>${escapeHtml(formatValue((environment.server||{}).host,"-"))}</td><td><div class="tag-row">${renderProductChips(environment.products)}</div></td><td>${renderStatusPill(overview.status||"configured")}</td><td>${escapeHtml(formatLocalTimestamp(overview.generatedAt,overview.generatedAtEpoch,"Not yet collected"))}</td><td><div class="row-actions"><button class="button" type="button" data-open-environment="${escapeHtml(environment.id)}">Open</button><button class="button" type="button" data-edit-environment="${escapeHtml(environment.id)}">Edit</button><button class="button is-danger" type="button" data-delete-environment="${escapeHtml(environment.id)}">Delete</button></div></td></tr>`;}).join("")}</tbody></table></div>`}</section></div>`;}
function renderNotificationsPage(){const notifications=state.notifications||{settings:DEFAULT_NOTIFICATION_SETTINGS,recipients:[]};const settings=normalizeNotificationSettings(notifications.settings);const recipients=coerceList(notifications.recipients);const recipient=selectedRecipient()||blankRecipient();return`<div class="content-stack">${renderSummaryTiles([{label:"Delivery",value:settings.enabled?"Enabled":"Disabled",copy:"Global notification delivery state."},{label:"Security Mode",value:String(settings.securityMode||"starttls").toUpperCase(),copy:"SMTP connection security."},{label:"Recipients",value:recipients.length,copy:"Notification recipients saved for the dashboard."},{label:"Sender",value:settings.senderEmail||"-",copy:"Sender address used for outbound email."}])}<div class="content-grid two-column"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">SMTP Settings</h3><p class="panel-copy">Save the mail settings used to send dashboard notifications.</p></div></div><form id="notification-settings-form" class="form"><div class="form-grid"><div class="field"><label for="smtp-host">SMTP Host</label><input id="smtp-host" name="smtpHost" value="${escapeHtml(settings.smtpHost||"")}" required></div><div class="field"><label for="smtp-port">SMTP Port</label><input id="smtp-port" name="smtpPort" type="number" value="${escapeHtml(settings.smtpPort||587)}" required></div><div class="field"><label for="smtp-username">SMTP Username</label><input id="smtp-username" name="smtpUsername" value="${escapeHtml(settings.smtpUsername||"")}"></div><div class="field"><label for="smtp-password">SMTP Password</label><input id="smtp-password" name="smtpPassword" type="password" value=""><p class="field-hint">${settings.hasPassword?"Stored SMTP password will be kept if this stays blank.":"Leave blank only when the relay does not require authentication."}</p></div><div class="field"><label for="sender-name">Sender Name</label><input id="sender-name" name="senderName" value="${escapeHtml(settings.senderName||"")}"></div><div class="field"><label for="sender-email">Sender Email</label><input id="sender-email" name="senderEmail" type="email" value="${escapeHtml(settings.senderEmail||"")}" required></div><div class="field"><label for="security-mode">Security Mode</label><select id="security-mode" name="securityMode"><option value="starttls" ${settings.securityMode==="starttls"?"selected":""}>STARTTLS</option><option value="ssl" ${settings.securityMode==="ssl"?"selected":""}>SSL</option><option value="none" ${settings.securityMode==="none"?"selected":""}>None</option></select></div><div class="field"><label class="checkbox-field" for="notifications-enabled"><input id="notifications-enabled" name="enabled" type="checkbox" ${settings.enabled?"checked":""}>Enable email notifications</label></div></div><div class="modal-footer"><button class="button is-primary" type="submit">Save SMTP Settings</button></div></form></section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Test Delivery</h3><p class="panel-copy">Send a test message using the currently saved SMTP configuration.</p></div></div><form id="notification-test-form" class="form"><div class="field"><label for="test-target-email">Test Email Target</label><input id="test-target-email" name="targetEmail" type="email" placeholder="name@example.com" required></div><div class="modal-footer"><button class="button" type="submit">Send Test Email</button></div></form></section></div><div class="content-grid two-column"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Recipients</h3><p class="panel-copy">Control who receives environment notifications.</p></div></div>${recipients.length===0?renderEmptyPanel("No recipients saved","Add at least one recipient to route warning and down notifications."):`<div class="table-wrap"><table><thead><tr><th>Name</th><th>Email</th><th>Severity</th><th>Enabled</th><th>Actions</th></tr></thead><tbody>${recipients.map(function(row){return`<tr><td>${escapeHtml(row.name||"-")}</td><td>${escapeHtml(row.email||"-")}</td><td>${escapeHtml(startCase(row.severity||"any"))}</td><td>${escapeHtml(row.enabled?"Yes":"No")}</td><td><div class="row-actions"><button class="button" type="button" data-edit-recipient="${escapeHtml(String(row.id))}">Edit</button><button class="button is-danger" type="button" data-delete-recipient="${escapeHtml(String(row.id))}">Delete</button></div></td></tr>`;}).join("")}</tbody></table></div>`}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">${recipient.id?"Edit Recipient":"Add Recipient"}</h3><p class="panel-copy">Add or update a recipient without leaving this page.</p></div></div><form id="recipient-form" class="form"><input type="hidden" name="id" value="${escapeHtml(recipient.id||"")}"><div class="form-grid"><div class="field"><label for="recipient-name">Name</label><input id="recipient-name" name="name" value="${escapeHtml(recipient.name||"")}" required></div><div class="field"><label for="recipient-email">Email</label><input id="recipient-email" name="email" type="email" value="${escapeHtml(recipient.email||"")}" required></div><div class="field"><label for="recipient-severity">Minimum Severity</label><select id="recipient-severity" name="severity"><option value="any" ${recipient.severity==="any"?"selected":""}>Any</option><option value="warning" ${recipient.severity==="warning"?"selected":""}>Warning</option><option value="critical" ${recipient.severity==="critical"?"selected":""}>Critical</option></select></div><div class="field"><label class="checkbox-field" for="recipient-enabled"><input id="recipient-enabled" name="enabled" type="checkbox" ${recipient.enabled?"checked":""}>Enabled</label></div></div><div class="modal-footer">${recipient.id?`<button class="button" type="button" data-reset-recipient>Cancel</button>`:""}<button class="button is-primary" type="submit">${recipient.id?"Save Recipient":"Add Recipient"}</button></div></form></section></div></div>`;}
function renderHelpPage(){const help=(state.appShell||{}).help||{};const checks=coerceList(help.checks);const notes=coerceList(help.notes);return`<div class="content-stack">${renderSummaryTiles([{label:"Version",value:formatValue(help.version,"unknown"),copy:"Current bundle version exposed by this running service."},{label:"Service Port",value:formatValue(help.port,"8081"),copy:"HTTP port used by the IAM dashboard service."},{label:"Scheduler Wake",value:`${formatValue(help.schedulerWakeMinutes,"5")} min`,copy:"How often the host scheduler wakes to check due environments."},{label:"Default Collector",value:`${formatValue(help.defaultCollectionMinutes,"60")} min`,copy:"Default per-environment interval used during setup."}])}<div class="content-grid two-column"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Product Details</h3><p class="panel-copy">Version and deployment identity for this IAM dashboard install.</p></div></div>${renderDefinitionList([{key:"Product",value:help.productName||"Oracle Identity & Access Management Dashboard"},{key:"Version",value:help.version||"unknown"},{key:"Package",value:help.packageName||"-"},{key:"Platform",value:help.platform||"-"},{key:"Service Name",value:help.serviceName||"iam-monitoring"},{key:"Service User",value:help.serviceUser||"iam-monitoring"}])}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Runtime Layout</h3><p class="panel-copy">Installed paths and generated runtime artifacts, similar to the CTERA support view.</p></div></div>${renderDefinitionList([{key:"Install Directory",value:help.installDirectory||"-"},{key:"Runtime Env File",value:help.runtimeEnvFile||"-"},{key:"SQLite Registry",value:help.databasePath||"-"},{key:"State Directory",value:help.stateDirectory||"-"},{key:"Runtime Env Directory",value:help.runtimeEnvDirectory||"-"},{key:"Snapshot Directory",value:help.snapshotDirectory||"-"},{key:"Job State Directory",value:help.jobStateDirectory||"-"},{key:"Log Directory",value:help.logDirectory||"-"},{key:"Scheduler Log",value:help.schedulerLogPath||"-"},{key:"Service Unit",value:help.serviceFile||"-"},{key:"Cron File",value:help.cronFile||"-"}])}</section></div><div class="content-grid two-column"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Health And Endpoints</h3><p class="panel-copy">Core service endpoint details for validation and troubleshooting.</p></div></div>${renderDefinitionList([{key:"Bind Host",value:help.host||"0.0.0.0"},{key:"Port",value:formatValue(help.port,"8081")},{key:"Health Path",value:help.healthPath||"/healthz"},{key:"Local Health URL",value:help.healthUrl||"-"}])}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Support Notes</h3><p class="panel-copy">Operational guidance carried into the product instead of hiding it in docs alone.</p></div></div>${notes.length===0?renderEmptyPanel("No notes loaded","Help notes were not returned by the service."):`<ul class="note-list">${notes.map(function(note){return`<li>${escapeHtml(note)}</li>`;}).join("")}</ul>`}</section></div><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Checks And Commands</h3><p class="panel-copy">These are the same kinds of checks admins expect during install, health validation, and troubleshooting.</p></div></div>${renderCommandTable(checks,"No support commands were returned by the service.")}</section></div>`;}
function renderOverviewPage(){const overview=selectedEnvironmentOverview()||{};const record=selectedEnvironmentRecord()||{};const dashboard=state.dashboard||{};const notes=coerceList(dashboard.notes);const oud=record.oud||{};const collection=record.collection||((dashboard.environment||{}).collection)||{};const bootstrap=record.bootstrap||((dashboard.environment||{}).bootstrap)||{};const job=dashboard.job||{};const lastCollection=formatLocalTimestamp(dashboard.generatedAt||overview.generatedAt,dashboard.generatedAtEpoch||overview.generatedAtEpoch,"Not yet collected");const lastBootstrapped=formatLocalTimestamp(bootstrap.lastBootstrappedAt,null,"-");return`<div class="content-stack">${renderSummaryTiles([{label:"Environment Type",value:uppercaseType(record.environmentType||overview.environmentType),copy:"Primary IAM workload selected for this environment."},{label:"Host",value:(record.server||{}).host||overview.host||"-",copy:"Primary SSH target used by the environment profile."},{label:"Bootstrap",value:startCase(bootstrap.status||"pending"),copy:"Initial SSH access is only used for bootstrap."},{label:"Schedule",value:collection.enabled===false?"Disabled":`${formatValue(collection.scheduleMinutes,defaultCollectionMinutes())} min`,copy:"Per-environment collector interval."},{label:"Healthy Checks",value:((overview.summary||{}).healthyApps)||0,copy:"Application checks returning healthy status."},{label:"Warnings",value:((overview.summary||{}).warningApps)||0,copy:"Checks responding with partial degradation."},{label:"Down",value:((overview.summary||{}).downApps)||0,copy:"Checks that are currently failing."},{label:"Last Job",value:startCase(job.status||"idle"),copy:"Current Run Jobs Now collector state."}])}<div class="content-grid two-column"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Environment Profile</h3><p class="panel-copy">Saved environment details that drive monitoring and operations.</p></div></div>${renderDefinitionList([{key:"Environment Name",value:record.name||overview.name||"-"},{key:"Description",value:record.description||overview.description||"-"},{key:"Environment Type",value:uppercaseType(record.environmentType||overview.environmentType)},{key:"SSH Host",value:(record.server||{}).host||overview.host||"-"},{key:"SSH Port",value:formatValue((record.server||{}).port,"22")},{key:"SSH Username",value:(record.server||{}).username||"-"}])}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Collection Profile</h3><p class="panel-copy">Bootstrap and scheduler state for this environment.</p></div></div>${renderDefinitionList([{key:"Last Collection",value:lastCollection},{key:"Last Job Status",value:startCase(job.status||"idle")},{key:"Bootstrap Status",value:startCase(bootstrap.status||"pending")},{key:"Bootstrap Time",value:lastBootstrapped},{key:"Collector Interval",value:collection.enabled===false?"Disabled":`${formatValue(collection.scheduleMinutes,defaultCollectionMinutes())} minutes`},{key:"Runtime Config",value:bootstrap.runtimeEnvPath||"-"}])}</section></div>${normalizeEnvironmentType(record.environmentType,"")==="oud"?`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">OUD Registration</h3><p class="panel-copy">OUD fields stay explicit so SSH access is not mixed with directory credentials.</p></div></div>${renderDefinitionList([{key:"OUD Host",value:oud.host||(record.server||{}).host||"-"},{key:"OUD DOMAIN_HOME",value:oud.domainHome||"-"},{key:"OUD INSTANCE_HOME",value:oud.instanceHome||"-"},{key:"Directory Manager Username",value:oud.bindDn||"cn=Directory Manager"},{key:"LDAP Port",value:formatValue(oud.ldapPort,"1389")},{key:"Admin Port",value:formatValue(oud.adminPort,"4444")}])}</section>`:`<section class="placeholder-panel"><h4>Detailed Product Registration Coming Next</h4><p>OAM, OIG, and OID detailed forms are intentionally left for the next expansion. This environment keeps the basic registry entry for now.</p></section>`}<section class="panel"><div class="panel-header"><div><h3 class="panel-title">Bootstrap Notes</h3><p class="panel-copy">The bootstrap flow matches the CTERA pattern for first-time access.</p></div></div><ul class="note-list"><li>Bootstrap uses the saved SSH user, password, or initial private key one time.</li><li>After bootstrap, the dashboard switches this environment to the installed runtime key for ongoing collection.</li><li>Run Jobs Now uses the saved runtime profile so you can collect fresh data immediately.</li></ul></section>${notes.length>0?`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">Collection Notes</h3><p class="panel-copy">Saved runtime notes for this environment.</p></div></div><ul class="note-list">${notes.map(function(note){return`<li>${escapeHtml(note)}</li>`;}).join("")}</ul></section>`:""}</div>`;}
function renderServerMetricsPage(){const record=selectedEnvironmentRecord()||{};const dashboard=state.dashboard||{};const server=dashboard.server||{};const uptime=server.uptime||{};const memory=server.memory||{};const rootDisk=server.rootDisk||{};const refreshDisk=server.refreshDisk||{};const cpuBreakdown=uptime.cpuBreakdown||{};const lastAttempt=formatLocalTimestamp(dashboard.generatedAt,dashboard.generatedAtEpoch,"-");if(!server.reachable){const pending=dashboard.status==="configured";return`<div class="content-stack">${renderSummaryTiles([{label:"Environment Host",value:(record.server||{}).host||"-",copy:"Configured SSH target."},{label:"SSH Mode",value:sshModeLabel(resolveSshMode(record.server||{})),copy:"Current saved SSH access model."},{label:"Status",value:pending?"Not Yet Collected":"Unreachable",copy:pending?"Run bootstrap and collect once, or wait for the scheduler.":"The server could not be collected with the current connection settings."},{label:"Last Attempt",value:lastAttempt,copy:"Latest collection attempt."}])}<section class="panel"><div class="panel-header"><div><h3 class="panel-title">${pending?"Collector Pending":"Connection Error"}</h3><p class="panel-copy">${pending?"This environment does not have a saved collector snapshot yet.":"This page only shows environment server details, and this target is currently unavailable."}</p></div></div><p class="table-note">${escapeHtml(server.error||dashboard.collectorError||(pending?"No collector snapshot has been saved yet.":"The environment server is not reachable with the current SSH settings."))}</p></section></div>`;}return`<div class="content-stack">${renderSummaryTiles([{label:"CPU Count",value:formatValue(uptime.cpuCount,"-"),copy:"Processors reported by the environment host."},{label:"Load Average (1m)",value:formatValue(uptime.load1,"-"),copy:"Immediate host load average."},{label:"Memory Used",value:formatPercent(memory.usedPercent),copy:memory.totalMb?`${memory.usedMb} MB of ${memory.totalMb} MB`:"Memory details from /proc/meminfo."},{label:"Root Disk Used",value:formatPercent(rootDisk.usedPercent),copy:rootDisk.size?`${rootDisk.used} of ${rootDisk.size}`:"Primary filesystem usage."},{label:"CPU User",value:formatPercent(cpuBreakdown.userPercent),copy:"User-space CPU consumption from /proc/stat."},{label:"CPU System",value:formatPercent(cpuBreakdown.systemPercent),copy:"Kernel CPU consumption from /proc/stat."},{label:"CPU IO Wait",value:formatPercent(cpuBreakdown.ioWaitPercent),copy:"Storage wait time from /proc/stat."},{label:"Uptime Seconds",value:formatValue(uptime.uptimeSeconds,"-"),copy:"Raw uptime seconds from /proc/uptime."}])}<div class="content-grid two-column"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Server Identity</h3><p class="panel-copy">Connection profile and observed host information.</p></div></div>${renderDefinitionList([{key:"Configured Host",value:(record.server||{}).host||"-"},{key:"Actual Hostname",value:server.actualHostname||"-"},{key:"Operating System",value:server.os||"-"},{key:"Kernel",value:server.kernel||"-"},{key:"SSH Port",value:formatValue((record.server||{}).port,"22")},{key:"SSH Username",value:(record.server||{}).username||"-"},{key:"SSH Mode",value:sshModeLabel(resolveSshMode(record.server||{}))}])}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Utilization</h3><p class="panel-copy">Core server metrics for load, CPU, memory, and disk.</p></div></div>${renderDefinitionList([{key:"Load Average (1m / 5m / 15m)",value:`${formatValue(uptime.load1,"-")} / ${formatValue(uptime.load5,"-")} / ${formatValue(uptime.load15,"-")}`},{key:"CPU Pressure",value:formatPercent(uptime.cpuPressure)},{key:"CPU Idle",value:formatPercent(cpuBreakdown.idlePercent)},{key:"Memory Total",value:formatMb(memory.totalMb)},{key:"Memory Available",value:formatMb(memory.availableMb)},{key:"Root Disk",value:rootDisk.size?`${rootDisk.used} / ${rootDisk.size} (${formatPercent(rootDisk.usedPercent)})`:"-"},{key:"Refresh Disk",value:refreshDisk.size?`${refreshDisk.used} / ${refreshDisk.size} (${formatPercent(refreshDisk.usedPercent)})`:"-"}])}</section></div><div class="content-grid two-column"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Discovered Scripts</h3><p class="panel-copy">Scripts visible in the configured server metrics directory.</p></div></div>${renderCodeList(server.scripts,"No control scripts were discovered for this environment.")}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Matched Processes</h3><p class="panel-copy">Processes discovered with the current product matchers.</p></div></div>${renderCodeList(server.processes,"No matching processes were discovered for this environment.")}</section></div></div>`;}
function renderOudMetrics(record,dashboard){const metrics=((dashboard.productMetrics||{}).oud)||{};const listeners=coerceList(metrics.listeners);const backends=coerceList(metrics.backends);const checks=coerceList(dashboard.appChecks).filter(function(check){return check.product==="oud";});return`<div class="content-stack">${renderSummaryTiles([{label:"Run Status",value:metrics.serverRunStatus||"Unavailable",copy:"Current OUD runtime state."},{label:"Open Connections",value:formatValue(metrics.openConnections,"-"),copy:"Connections reported by the OUD runtime."},{label:"Listeners",value:listeners.length,copy:"Listener endpoints returned by the status utility."},{label:"Backends",value:backends.length,copy:"Backend entries returned by the status utility."}])}<div class="content-grid two-column"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">OUD Runtime Details</h3><p class="panel-copy">Runtime and directory details returned by the OUD status and LDAP checks.</p></div></div>${renderDefinitionList([{key:"Version",value:metrics.version||metrics.vendorVersion||"-"},{key:"Java Version",value:metrics.javaVersion||"-"},{key:"Host Name",value:metrics.hostName||"-"},{key:"Naming Contexts",value:coerceList(metrics.namingContexts).join(", ")||"-"},{key:"Installation Path",value:metrics.installationPath||(record.oud||{}).domainHome||"-"},{key:"Instance Path",value:metrics.instancePath||(record.oud||{}).instanceHome||"-"},{key:"Administration Connector",value:metrics.administrationConnector||"-"}])}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Saved OUD Registration</h3><p class="panel-copy">The OUD registration remains distinct from SSH access.</p></div></div>${renderDefinitionList([{key:"OUD Host",value:(record.oud||{}).host||(record.server||{}).host||"-"},{key:"OUD DOMAIN_HOME",value:(record.oud||{}).domainHome||"-"},{key:"OUD INSTANCE_HOME",value:(record.oud||{}).instanceHome||"-"},{key:"Directory Manager Username",value:(record.oud||{}).bindDn||"cn=Directory Manager"},{key:"LDAP Port",value:formatValue((record.oud||{}).ldapPort,"1389")},{key:"Admin Port",value:formatValue((record.oud||{}).adminPort,"4444")}])}</section></div><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Listeners</h3><p class="panel-copy">Listener state returned by the OUD status command.</p></div></div>${listeners.length===0?renderEmptyPanel("No listener data",metrics.error||"Listener details were not returned for this environment."):`<div class="table-wrap"><table><thead><tr><th>Address:Port</th><th>Protocol</th><th>State</th></tr></thead><tbody>${listeners.map(function(listener){return`<tr><td>${escapeHtml(formatValue(listener.addressPort,"-"))}</td><td>${escapeHtml(formatValue(listener.protocol,"-"))}</td><td>${escapeHtml(formatValue(listener.state,"-"))}</td></tr>`;}).join("")}</tbody></table></div>`}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Backends</h3><p class="panel-copy">Backend summary returned by the OUD status command.</p></div></div>${backends.length===0?renderEmptyPanel("No backend data","Backend details were not returned for this environment."):`<div class="table-wrap"><table><thead><tr><th>Base DN</th><th>Backend ID</th><th>Entries</th><th>Replication</th></tr></thead><tbody>${backends.map(function(backend){return`<tr><td>${escapeHtml(formatValue(backend.baseDn,"-"))}</td><td>${escapeHtml(formatValue(backend.backendId,"-"))}</td><td>${escapeHtml(formatValue(backend.entries,"-"))}</td><td>${escapeHtml(formatValue(backend.replication,"-"))}</td></tr>`;}).join("")}</tbody></table></div>`}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Application Checks</h3><p class="panel-copy">OUD-related checks registered for this environment.</p></div></div>${renderChecksTable(checks,"No OUD application checks are configured yet.")}</section></div>`;}
function renderOamMetrics(record,dashboard){const runtime=(((dashboard.productMetrics||{}).oam)||{}).runtime||{};const checks=coerceList(dashboard.appChecks).filter(function(check){return check.product==="oam";});return`<div class="content-stack">${renderSummaryTiles([{label:"Running Servers",value:formatValue(runtime.runningServers,"0"),copy:"Detected OAM WebLogic JVMs."},{label:"Expected Servers",value:coerceList(runtime.expectedServers).length||0,copy:"Configured OAM runtime server names."},{label:"Missing Servers",value:coerceList(runtime.missingServers).length||0,copy:"Configured OAM servers not currently running."},{label:"Application Checks",value:checks.length,copy:"OAM checks configured for this environment."}])}<section class="panel"><div class="panel-header"><div><h3 class="panel-title">OAM Runtime</h3><p class="panel-copy">OAM runtime is derived from the WebLogic domain metrics on this environment.</p></div></div>${runtime.error?`<p class="table-note">${escapeHtml(runtime.error)}</p>`:renderRuntimeTable(runtime.servers,"No OAM WebLogic runtimes were discovered for this environment.")}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">OAM Checks</h3><p class="panel-copy">Default OAM application checks are attached automatically when the environment is configured for OAM.</p></div></div>${renderChecksTable(checks,"No OAM checks are configured yet.")}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Saved Runtime Profile</h3><p class="panel-copy">Current OAM/WebLogic defaults saved on the environment record.</p></div></div>${renderDefinitionList([{key:"JSTAT Path",value:((record.weblogic||{}).jstatPath)||"-"},{key:"Server Names",value:coerceList((record.weblogic||{}).serverNames).join(", ")||"-"},{key:"SSH Host",value:(record.server||{}).host||"-"},{key:"SSH Mode",value:sshModeLabel(resolveSshMode(record.server||{}))}])}</section></div>`;}
function renderOigMetrics(record,dashboard){const metrics=((dashboard.productMetrics||{}).oig)||{};const checks=coerceList(metrics.checks);return`<div class="content-stack">${renderSummaryTiles([{label:"OIG Enabled",value:metrics?"Yes":"No",copy:"Current OIG product state for this environment."},{label:"Configured Checks",value:checks.length,copy:"OIG checks currently saved for this environment."},{label:"Environment Type",value:uppercaseType(record.environmentType),copy:"Primary product type for the selected environment."},{label:"SSH Host",value:(record.server||{}).host||"-",copy:"Current SSH target for future OIG collection."}])}<section class="panel"><div class="panel-header"><div><h3 class="panel-title">OIG Metrics</h3><p class="panel-copy">OIG is wired for environment registration now, with room for deeper runtime metrics next.</p></div></div><p class="table-note">${escapeHtml(metrics.message||"OIG runtime metrics will be expanded next.")}</p></section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">OIG Checks</h3><p class="panel-copy">OIG check definitions saved for this environment.</p></div></div>${renderChecksTable(checks,"This environment is ready for OIG expansion, but no OIG checks are configured yet.")}</section></div>`;}
function renderWebLogicMetrics(record,dashboard){const metrics=((dashboard.productMetrics||{}).weblogic)||{};return`<div class="content-stack">${renderSummaryTiles([{label:"Running Servers",value:formatValue(metrics.runningServers,"0"),copy:"Detected WebLogic JVMs on the target host."},{label:"Expected Servers",value:coerceList(metrics.expectedServers).length||0,copy:"Configured server names saved on the environment."},{label:"Missing Servers",value:coerceList(metrics.missingServers).length||0,copy:"Configured WebLogic servers not currently running."},{label:"SSH Access",value:sshModeLabel(resolveSshMode(record.server||{})),copy:"The same environment SSH profile is reused here."}])}<section class="panel"><div class="panel-header"><div><h3 class="panel-title">WebLogic Runtime</h3><p class="panel-copy">WebLogic JVMs, heap visibility, and configured server names for this environment.</p></div></div>${metrics.error?`<p class="table-note">${escapeHtml(metrics.error)}</p>`:renderRuntimeTable(metrics.servers,"No WebLogic runtimes were discovered for this environment.")}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Saved WebLogic Profile</h3><p class="panel-copy">Current WebLogic defaults saved on the environment record.</p></div></div>${renderDefinitionList([{key:"JSTAT Path",value:((record.weblogic||{}).jstatPath)||"-"},{key:"Configured Server Names",value:coerceList((record.weblogic||{}).serverNames).join(", ")||"-"},{key:"Missing Server Names",value:coerceList(metrics.missingServers).join(", ")||"-"},{key:"SSH Host",value:(record.server||{}).host||"-"}])}</section></div>`;}
function renderApplicationMetricsPage(){const record=selectedEnvironmentRecord()||{};const dashboard=state.dashboard||{};const products=record.products||{};const applicationMeta=applicationSectionMeta(record);const tabs=[{id:"oud",label:"OUD",enabled:Boolean(products.oud)},{id:"oam",label:"OAM",enabled:Boolean(products.oam)},{id:"oig",label:"OIG",enabled:Boolean(products.oig)},{id:"weblogic",label:"WebLogic",enabled:Boolean(products.weblogic||products.oam||products.oig)}];const activeTab=state.activeProductTab=normalizeProductTab(state.activeProductTab,record);let body=renderEmptyPanel("Product tab not available","Choose a product tab to view application metrics.");if(activeTab==="oud")body=products.oud?renderOudMetrics(record,dashboard):renderEmptyPanel("OUD not enabled","This environment is not currently configured as an OUD environment.");else if(activeTab==="oam")body=products.oam?renderOamMetrics(record,dashboard):renderEmptyPanel("OAM not enabled","This environment is not currently configured as an OAM environment.");else if(activeTab==="oig")body=products.oig?renderOigMetrics(record,dashboard):renderEmptyPanel("OIG not enabled","This environment is not currently configured as an OIG environment.");else if(activeTab==="weblogic")body=(products.weblogic||products.oam||products.oig)?renderWebLogicMetrics(record,dashboard):renderEmptyPanel("WebLogic not enabled","This environment does not currently expose a WebLogic runtime profile.");const panelTitle=applicationMeta.label==="Application Metrics"?"Product Tabs":`${applicationMeta.label} Views`;const panelCopy=applicationMeta.label==="Application Metrics"?"Application metrics stay separate from server metrics and are grouped by product tab.":`${applicationMeta.label} runtime metrics and checks for this environment.`;return`<div class="content-stack"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">${escapeHtml(panelTitle)}</h3><p class="panel-copy">${escapeHtml(panelCopy)}</p></div></div><div class="tab-row">${tabs.map(function(tab){return`<button class="tab-button ${activeTab===tab.id?"is-active":""} ${tab.enabled?"":"is-disabled"}" type="button" data-product-tab="${escapeHtml(tab.id)}"><span>${escapeHtml(tab.label)}</span><span class="muted">${tab.enabled?"Enabled":"Later"}</span></button>`;}).join("")}</div></section>${body}</div>`;}
function renderOperationsPage(){const record=selectedEnvironmentRecord()||{};const dashboard=state.dashboard||{};const operations=record.operations||{};const bootstrap=record.bootstrap||((dashboard.environment||{}).bootstrap)||{};const collection=record.collection||((dashboard.environment||{}).collection)||{};const job=dashboard.job||{};const bootstrapReady=bootstrap.status==="ready";const scheduleLabel=collection.enabled===false?"Disabled":`${formatValue(collection.scheduleMinutes,defaultCollectionMinutes())} minutes`;const lastBootstrapped=formatLocalTimestamp(bootstrap.lastBootstrappedAt,null,"-");const lastCollection=formatLocalTimestamp(dashboard.generatedAt,dashboard.generatedAtEpoch,"Not yet collected");const startedAt=formatLocalTimestamp(job.startedAt,null,"-");const finishedAt=formatLocalTimestamp(job.finishedAt,null,"-");const tail=renderTerminalSnippet(job.tail,"Collector log output will appear here after the first run.");return`<div class="content-stack">${renderSummaryTiles([{label:"Bootstrap",value:startCase(bootstrap.status||"pending"),copy:"Initial SSH access is only used for bootstrap."},{label:"Collector Schedule",value:scheduleLabel,copy:"Per-environment collector interval."},{label:"Run Jobs Now",value:startCase(job.status||"idle"),copy:"Current collector job state."},{label:"SSH Access",value:sshModeLabel(resolveSshMode(record.server||{})),copy:"Saved runtime SSH profile after bootstrap."}])}<div class="content-grid two-column"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Bootstrap Runtime Access</h3><p class="panel-copy">Match the CTERA pattern: bootstrap once with the initial SSH login, then switch to the installed runtime key.</p></div>${bootstrapReady?"":`<div class="panel-actions"><button class="button is-primary" type="button" data-run-bootstrap>Run Bootstrap</button></div>`}</div>${renderDefinitionList([{key:"Bootstrap Status",value:startCase(bootstrap.status||"pending")},{key:"Initial SSH Mode",value:sshModeLabel(bootstrap.initialSshMode||resolveSshMode(record.server||{}))},{key:"Runtime Key Path",value:bootstrap.runtimeKeyPath||"-"},{key:"Runtime Config",value:bootstrap.runtimeEnvPath||"-"},{key:"Last Bootstrapped",value:lastBootstrapped}])}<ul class="note-list"><li>Bootstrap uses the saved SSH user and password or the saved initial private key one time.</li><li>After bootstrap, the dashboard uses the installed runtime key for ongoing Run Jobs Now and scheduled collection.</li><li>For non-root SSH users, sudo must work without a password after the runtime key is installed.</li></ul></section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Run Jobs Now</h3><p class="panel-copy">Collect fresh environment data immediately instead of waiting for the next scheduler window.</p></div><div class="panel-actions"><button class="button" type="button" data-run-jobs ${job.status==="running"?"disabled":""}>${job.status==="running"?"Running...":"Run Jobs Now"}</button></div></div>${renderDefinitionList([{key:"Collector Status",value:startCase(job.status||"idle")},{key:"Started At",value:startedAt},{key:"Finished At",value:finishedAt},{key:"Trigger",value:startCase(job.trigger||"-")},{key:"Log Path",value:job.logPath||"-"}])}${tail}</section></div><div class="content-grid two-column"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Scheduler Profile</h3><p class="panel-copy">The host scheduler wakes every 5 minutes and runs this environment only when its saved interval is due.</p></div></div>${renderDefinitionList([{key:"Enabled",value:collection.enabled===false?"No":"Yes"},{key:"Collector Interval",value:scheduleLabel},{key:"Last Collection",value:lastCollection},{key:"Last Dashboard Status",value:statusLabel(dashboard.status||"configured")}])}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Installer And Upgrade Reuse</h3><p class="panel-copy">Install and upgrade reuse the same saved environment profile without duplicating connection settings.</p></div></div>${renderDefinitionList([{key:"Install Method",value:operations.installMethod||"environment_ssh"},{key:"Upgrade Method",value:operations.upgradeMethod||"environment_ssh"},{key:"SSH Host",value:(record.server||{}).host||"-"},{key:"SSH Username",value:(record.server||{}).username||"-"},{key:"SSH Mode",value:sshModeLabel(resolveSshMode(record.server||{}))}])}</section></div></div>`;}
function renderEnvironmentForm(environment,isEdit){const type=normalizeEnvironmentType(environment.environmentType,"oud");const server=environment.server||{};const oud=environment.oud||{};const sshMode=resolveSshMode(server);const collection=environment.collection||{};return`<form id="environment-form" class="form"><section class="form-section"><div class="form-section-header"><h4>Environment Basics</h4><p class="form-section-copy">Start with the environment identity and product type.</p></div><div class="form-grid three-column"><div class="field"><label for="env-name">Environment Name</label><input id="env-name" name="name" value="${escapeHtml(environment.name||"")}" required></div><div class="field field-span-2"><label for="env-description">Description</label><input id="env-description" name="description" value="${escapeHtml(environment.description||"")}"></div><div class="field"><label for="environment-type">Environment Type</label><select id="environment-type" name="environmentType"><option value="oud" ${type==="oud"?"selected":""}>OUD</option><option value="oam" ${type==="oam"?"selected":""}>OAM</option><option value="oig" ${type==="oig"?"selected":""}>OIG</option><option value="oid" ${type==="oid"?"selected":""}>OID</option></select></div></div></section><section class="form-section" data-environment-panel="oud"><div class="form-section-header"><h4>Endpoint And Paths</h4><p class="form-section-copy">Core OUD host, SSH port, and filesystem paths.</p></div><div class="form-grid"><div class="field"><label for="oud-host">OUD Host</label><input id="oud-host" name="oudHost" value="${escapeHtml(oud.host||server.host||"")}"></div><div class="field"><label for="server-port">OUD SSH Port</label><input id="server-port" name="serverPort" type="number" value="${escapeHtml(server.port||22)}"></div><div class="field"><label for="oud-domain-home">OUD DOMAIN_HOME</label><input id="oud-domain-home" name="oudDomainHome" value="${escapeHtml(oud.domainHome||"")}"></div><div class="field"><label for="oud-instance-home">OUD INSTANCE_HOME</label><input id="oud-instance-home" name="oudInstanceHome" value="${escapeHtml(oud.instanceHome||"")}"></div><div class="field"><label for="oud-ldap-port">LDAP Port</label><input id="oud-ldap-port" name="oudLdapPort" type="number" value="${escapeHtml(oud.ldapPort||1389)}"></div><div class="field"><label for="oud-admin-port">Admin Port</label><input id="oud-admin-port" name="oudAdminPort" type="number" value="${escapeHtml(oud.adminPort||4444)}"></div></div></section><section class="form-section" data-environment-panel="oud"><div class="form-section-header"><h4>SSH Access</h4><p class="form-section-copy">SSH access is kept separate from Directory Manager credentials.</p></div><div class="form-grid"><div class="field"><label for="server-ssh-mode">SSH Authentication</label><select id="server-ssh-mode" name="serverSshMode">${SSH_MODE_CHOICES.map(function(choice){return`<option value="${escapeHtml(choice.id)}" ${sshMode===choice.id?"selected":""}>${escapeHtml(choice.label)}</option>`;}).join("")}</select></div><div class="field"><label for="server-username">OUD SSH Username</label><input id="server-username" name="serverUsername" value="${escapeHtml(server.username||"root")}"></div><div class="field" data-ssh-field="password"><label for="server-password">SSH Password</label><input id="server-password" name="serverPassword" type="password" value=""><p class="field-hint">${server.hasPassword?"Stored SSH password will be kept if this stays blank.":"Provide the SSH password for password-based access."}</p></div><div class="field hidden" data-ssh-field="key"><label for="server-key-path">Private Key Path</label><input id="server-key-path" name="serverKeyPath" value="${escapeHtml(server.privateKeyPath||"")}"></div><div class="field hidden" data-ssh-field="passphrase"><label for="server-passphrase">Passphrase</label><input id="server-passphrase" name="serverPassphrase" type="password" value=""><p class="field-hint">${server.hasPassphrase?"Stored passphrase will be kept if this stays blank.":"Use this only when the key is encrypted."}</p></div><div class="field field-span-2"><p id="ssh-mode-note" class="field-hint"></p></div><div class="field field-span-2"><p class="field-hint">Bootstrap uses this initial SSH access one time. After bootstrap, the dashboard switches the environment to its installed runtime SSH key for ongoing Run Jobs Now and scheduled collection.</p></div></div></section><section class="form-section" data-environment-panel="oud"><div class="form-section-header"><h4>Directory Manager Credentials</h4><p class="form-section-copy">These credentials are used for OUD runtime and LDAP checks only.</p></div><div class="form-grid"><div class="field"><label for="oud-bind-dn">Directory Manager Username</label><input id="oud-bind-dn" name="oudBindDn" value="${escapeHtml(oud.bindDn||"cn=Directory Manager")}"></div><div class="field"><label for="oud-bind-password">Directory Manager Password</label><input id="oud-bind-password" name="oudBindPassword" type="password" value=""><p class="field-hint">${oud.hasBindPassword?"Stored Directory Manager password will be kept if this stays blank.":"Provide the Directory Manager password used for OUD status and LDAP checks."}</p></div></div></section><section class="form-section"><div class="form-section-header"><h4>Collection Schedule</h4><p class="form-section-copy">Each environment manages its own collector cadence, and the host scheduler wakes every 5 minutes.</p></div><div class="form-grid"><div class="field"><label class="checkbox-field" for="collection-enabled"><input id="collection-enabled" name="collectionEnabled" type="checkbox" ${collection.enabled===false?"":"checked"}>Enable scheduled collection for this environment</label></div><div class="field"><label for="collection-schedule-minutes">Collector Interval Minutes</label><input id="collection-schedule-minutes" name="collectionScheduleMinutes" type="number" min="5" value="${escapeHtml(collection.scheduleMinutes||defaultCollectionMinutes())}"></div></div></section><section class="form-section hidden" data-environment-panel="placeholder"><div class="form-section-header"><h4>Detailed Product Form Coming Next</h4><p id="pending-type-copy" class="form-section-copy">Only the OUD detailed form is implemented right now. This environment can still be registered with the basic fields above.</p></div></section><div class="modal-footer"><button class="button" type="button" data-close-modal>Cancel</button><button class="button" type="submit">${isEdit?"Save Environment":"Create Environment"}</button><button class="button is-primary" type="button" data-save-and-bootstrap>${isEdit?"Save And Bootstrap":"Create And Bootstrap"}</button></div></form>`;}
function renderEnvironmentModal(){if(!state.environmentModalOpen){refs.environmentModalBackdrop.classList.add("hidden");refs.environmentModalBody.innerHTML="";return;}const environment=editingEnvironmentRecord()||blankEnvironment();const isEdit=Boolean(state.editingEnvironmentId);refs.environmentModalBackdrop.classList.remove("hidden");refs.environmentModalCrumb.textContent=isEdit?"Administration / Environments / Edit":"Administration / Environments / Create";refs.environmentModalTitle.textContent=isEdit?`Edit ${environment.name||"Environment"}`:"Create Environment";refs.environmentModalBody.innerHTML=renderEnvironmentForm(environment,isEdit);syncEnvironmentFormDisplay();}
function syncEnvironmentFormDisplay(){const form=document.getElementById("environment-form");if(!form)return;const environmentType=normalizeEnvironmentType((form.elements.environmentType||{}).value,"oud");const sshMode=(form.elements.serverSshMode||{}).value||"root_password";const isOud=environmentType==="oud";const usesKey=sshModeUsesKey(sshMode);const usesSudo=sshModeUsesSudo(sshMode);const usesRoot=sshMode.startsWith("root_");form.querySelectorAll("[data-environment-panel='oud']").forEach(function(panel){panel.classList.toggle("hidden",!isOud);});form.querySelectorAll("[data-environment-panel='placeholder']").forEach(function(panel){panel.classList.toggle("hidden",isOud);});const pendingCopy=document.getElementById("pending-type-copy");if(pendingCopy)pendingCopy.textContent=`${uppercaseType(environmentType)} detailed fields are intentionally left for the next expansion. The environment can be registered now with the basic fields above.`;form.querySelectorAll("[data-ssh-field='password']").forEach(function(field){field.classList.toggle("hidden",usesKey||!isOud);});form.querySelectorAll("[data-ssh-field='key']").forEach(function(field){field.classList.toggle("hidden",!usesKey||!isOud);});form.querySelectorAll("[data-ssh-field='passphrase']").forEach(function(field){field.classList.toggle("hidden",!usesKey||!isOud);});const usernameInput=form.elements.serverUsername;if(usernameInput){if(usesRoot){usernameInput.value="root";usernameInput.readOnly=true;usernameInput.dataset.rootManaged="1";}else{if(usernameInput.dataset.rootManaged==="1"&&String(usernameInput.value).trim()==="root")usernameInput.value="";usernameInput.readOnly=false;usernameInput.dataset.rootManaged="0";}}const scheduleInput=form.elements.collectionScheduleMinutes;if(scheduleInput&&form.elements.collectionEnabled){scheduleInput.disabled=!form.elements.collectionEnabled.checked;}const note=document.getElementById("ssh-mode-note");if(note){if(sshMode==="root_password")note.textContent="Use root with an initial SSH password for bootstrap. After bootstrap, the dashboard switches to its installed runtime key.";else if(sshMode==="user_password_sudo")note.textContent="Use a non-root SSH account with an initial password for bootstrap, then elevate with sudo. After bootstrap, the dashboard switches to its installed runtime key.";else if(sshMode==="root_key")note.textContent="Use an initial root private key for bootstrap. After bootstrap, the dashboard still switches to its installed runtime key.";else note.textContent="Use an initial non-root private key for bootstrap, then elevate with sudo. After bootstrap, the dashboard switches to its installed runtime key.";if(usesSudo)note.textContent+=" Sudo is expected for environment commands in this mode.";}}
function readEnvironmentForm(){const form=document.getElementById("environment-form");if(!form)throw new Error("Environment form is not available.");const current=editingEnvironmentRecord()||blankEnvironment();const previousType=normalizeEnvironmentType(current.environmentType,"");const environmentType=normalizeEnvironmentType(form.elements.environmentType.value,"oud");const name=String(form.elements.name.value||"").trim();const description=String(form.elements.description.value||"").trim();if(!name)throw new Error("Environment name is required.");const payload={id:current.id||"",name:name,description:description,environmentType:environmentType,products:productsForEnvironmentType(environmentType),serverMetrics:{scriptDirectory:((current.serverMetrics||{}).scriptDirectory)||"/refresh/home/auto/bin",processMatchers:previousType===environmentType&&coerceList((current.serverMetrics||{}).processMatchers).length>0?coerceList((current.serverMetrics||{}).processMatchers):defaultProcessMatchersForType(environmentType)},weblogic:Object.assign({jstatPath:"/refresh/home/jdk-21.0.5/bin/jstat",serverNames:["AdminServer","oam_server1"]},current.weblogic||{}),oam:Object.assign({checks:[]},current.oam||{}),oig:Object.assign({checks:[]},current.oig||{}),collection:{enabled:Boolean(form.elements.collectionEnabled.checked),scheduleMinutes:Math.max(5,parseInt(form.elements.collectionScheduleMinutes.value,10)||defaultCollectionMinutes())},bootstrap:Object.assign({},current.bootstrap||blankEnvironment().bootstrap||{}),operations:Object.assign({installMethod:"environment_ssh",upgradeMethod:"environment_ssh"},current.operations||{})};if(environmentType==="oud"){const oudHost=String(form.elements.oudHost.value||"").trim();const sshMode=String(form.elements.serverSshMode.value||"root_password");const isKeyMode=sshModeUsesKey(sshMode);const sshPort=parseInt(form.elements.serverPort.value,10)||22;const username=sshMode.startsWith("root_")?"root":String(form.elements.serverUsername.value||"").trim();if(!oudHost)throw new Error("OUD Host is required.");if(!username)throw new Error("OUD SSH Username is required.");payload.server={mode:"ssh",host:oudHost,port:sshPort,username:username,sshMode:sshMode,authType:isKeyMode?"private_key":"password",sudoRequired:sshModeUsesSudo(sshMode),password:isKeyMode?"":String(form.elements.serverPassword.value||""),privateKeyPath:isKeyMode?String(form.elements.serverKeyPath.value||"").trim():"",passphrase:isKeyMode?String(form.elements.serverPassphrase.value||""):""};payload.oud={host:oudHost,domainHome:String(form.elements.oudDomainHome.value||"").trim(),instanceHome:String(form.elements.oudInstanceHome.value||"").trim(),bindDn:String(form.elements.oudBindDn.value||"").trim()||"cn=Directory Manager",bindPassword:String(form.elements.oudBindPassword.value||""),ldapPort:parseInt(form.elements.oudLdapPort.value,10)||1389,adminPort:parseInt(form.elements.oudAdminPort.value,10)||4444,checks:coerceList((current.oud||{}).checks)};}else{payload.server=Object.assign({},current.server||blankEnvironment().server||{});payload.oud=Object.assign({host:"",domainHome:"",instanceHome:"",bindDn:"cn=Directory Manager",bindPassword:"",ldapPort:1389,adminPort:4444,checks:[]},current.oud||{});}return payload;}
function clearCollectorRefresh(){if(collectorRefreshTimer){window.clearTimeout(collectorRefreshTimer);collectorRefreshTimer=0;}}
function syncCollectorRefresh(){clearCollectorRefresh();if(isAdministrationContext())return;const job=((state.dashboard||{}).job)||{};if(job.status==="running")collectorRefreshTimer=window.setTimeout(function(){loadAllData(false);},2500);}
function scheduleCollectorRefresh(){window.setTimeout(function(){loadAllData(false);},2500);}
async function runBootstrap(environmentId,environmentName){const result=await fetchJson(`/api/admin/environments/${encodeURIComponent(environmentId)}/bootstrap`,{method:"POST"});let message=`Bootstrap completed for ${environmentName||"the environment"}.`;if(result.collectorJobStarted)message+=" Collector started.";else if(result.collectorJobAlreadyRunning)message+=" Collector was already running.";setMessage(message,"success");await loadAllData(false);scheduleCollectorRefresh();return result;}
async function runJobsNow(environmentId,environmentName){const result=await fetchJson(`/api/admin/environments/${encodeURIComponent(environmentId)}/jobs/run`,{method:"POST"});let message=`Collector started for ${environmentName||"the environment"}.`;if(result.collectorJobAlreadyRunning)message=`Collector is already running for ${environmentName||"the environment"}.`;setMessage(message,"success");await loadAllData(false);scheduleCollectorRefresh();return result;}
async function saveEnvironment(runBootstrapAfterSave){const editingId=state.editingEnvironmentId;const payload=readEnvironmentForm();const result=await fetchJson(editingId?`/api/admin/environments/${encodeURIComponent(editingId)}`:"/api/admin/environments",{method:editingId?"PUT":"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});const environment=result.environment||{};state.environmentModalOpen=false;state.editingEnvironmentId=null;state.lastEnvironmentId=environment.id||state.lastEnvironmentId;await loadAllData(false);if(runBootstrapAfterSave&&environment.id){await runBootstrap(environment.id,environment.name||payload.name);return;}setMessage(`Environment ${environment.name||payload.name} saved.`,"success");}
async function deleteEnvironment(environmentId){if(!window.confirm("Delete this environment from the dashboard?"))return;await fetchJson(`/api/admin/environments/${encodeURIComponent(environmentId)}`,{method:"DELETE"});if(state.activeContext===environmentId){state.activeContext="administration";state.activeSection="admin-environments";}if(state.lastEnvironmentId===environmentId)state.lastEnvironmentId=null;if(state.editingEnvironmentId===environmentId){state.editingEnvironmentId=null;state.environmentModalOpen=false;}setMessage("Environment deleted.","success");await loadAllData(false);}
async function saveNotificationSettings(form){const payload={smtpHost:String(form.elements.smtpHost.value||"").trim(),smtpPort:parseInt(form.elements.smtpPort.value,10)||587,smtpUsername:String(form.elements.smtpUsername.value||"").trim(),smtpPassword:String(form.elements.smtpPassword.value||""),senderName:String(form.elements.senderName.value||"").trim(),senderEmail:String(form.elements.senderEmail.value||"").trim(),securityMode:String(form.elements.securityMode.value||"starttls").trim(),enabled:Boolean(form.elements.enabled.checked)};const result=await fetchJson("/api/admin/notifications/settings",{method:"PUT",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});state.notifications=state.notifications||{};state.notifications.settings=normalizeNotificationSettings(result.settings);state.notifications.recipients=coerceList((state.notifications||{}).recipients);setMessage("SMTP settings saved.","success");render();}
async function sendNotificationTest(form){const payload={targetEmail:String(form.elements.targetEmail.value||"").trim()};const result=await fetchJson("/api/admin/notifications/test",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});setMessage(`Test email sent to ${result.targetEmail}.`,"success");}
async function saveRecipient(form){const payload={id:String(form.elements.id.value||"").trim()||undefined,name:String(form.elements.name.value||"").trim(),email:String(form.elements.email.value||"").trim(),severity:String(form.elements.severity.value||"any").trim(),enabled:Boolean(form.elements.enabled.checked)};const result=await fetchJson("/api/admin/notifications/recipients",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});state.notifications=state.notifications||{};state.notifications.settings=normalizeNotificationSettings((state.notifications||{}).settings);state.notifications.recipients=coerceList(result.recipients);state.editingRecipientId=null;setMessage(`Recipient ${payload.name} saved.`,"success");render();}
async function deleteRecipient(recipientId){if(!window.confirm("Delete this recipient?"))return;const result=await fetchJson(`/api/admin/notifications/recipients/${encodeURIComponent(recipientId)}`,{method:"DELETE"});state.notifications=state.notifications||{};state.notifications.settings=normalizeNotificationSettings((state.notifications||{}).settings);state.notifications.recipients=coerceList(result.recipients);state.editingRecipientId=null;setMessage("Recipient deleted.","success");render();}
function openEnvironmentModal(environmentId){clearMessage();state.environmentModalOpen=true;state.editingEnvironmentId=environmentId||null;renderEnvironmentModal();}
function closeEnvironmentModal(){state.environmentModalOpen=false;state.editingEnvironmentId=null;renderEnvironmentModal();}
function renderPageContent(){if(!state.appShell)return renderEmptyPanel("Loading console","The dashboard is fetching its current state.");if(isAdministrationContext()){if(state.activeSection==="admin-notifications")return renderNotificationsPage();if(state.activeSection==="admin-help")return renderHelpPage();return renderEnvironmentRegistryPage();}if(!state.dashboard)return renderEmptyPanel("Loading environment","The selected environment dashboard is still being collected.");if(state.activeSection==="env-server")return renderServerMetricsPage();if(state.activeSection==="env-applications")return renderApplicationMetricsPage();if(state.activeSection==="env-operations")return renderOperationsPage();return renderOverviewPage();}
function render(){renderContextSwitcher();renderSidebar();renderHeader();renderMessage();refs.pageContent.innerHTML=renderPageContent();renderEnvironmentModal();syncCollectorRefresh();}
async function changeContext(context){clearMessage();state.activeContext=context||"administration";state.activeSection=defaultSectionForContext(state.activeContext);if(state.activeContext!=="administration")state.lastEnvironmentId=state.activeContext;persistState();await loadAllData(false);}
document.addEventListener("click",async function(event){const sectionButton=event.target.closest("[data-section]");if(sectionButton){state.activeSection=normalizeSectionForContext(state.activeContext,sectionButton.getAttribute("data-section"));persistState();render();return;}const openEnvironmentButton=event.target.closest("[data-open-environment]");if(openEnvironmentButton){await changeContext(openEnvironmentButton.getAttribute("data-open-environment"));return;}const createEnvironmentButton=event.target.closest("[data-create-environment]");if(createEnvironmentButton){openEnvironmentModal(null);return;}const editEnvironmentButton=event.target.closest("[data-edit-environment]");if(editEnvironmentButton){openEnvironmentModal(editEnvironmentButton.getAttribute("data-edit-environment"));return;}const deleteEnvironmentButton=event.target.closest("[data-delete-environment]");if(deleteEnvironmentButton){try{await deleteEnvironment(deleteEnvironmentButton.getAttribute("data-delete-environment"));}catch(error){setMessage(error.message,"error");}return;}const saveAndBootstrapButton=event.target.closest("[data-save-and-bootstrap]");if(saveAndBootstrapButton){try{await saveEnvironment(true);}catch(error){setMessage(error.message,"error");}return;}const runBootstrapButton=event.target.closest("[data-run-bootstrap]");if(runBootstrapButton){const current=selectedEnvironmentRecord()||selectedEnvironmentOverview()||{};try{await runBootstrap(current.id,current.name);}catch(error){setMessage(error.message,"error");}return;}const runJobsButton=event.target.closest("[data-run-jobs]");if(runJobsButton){const current=selectedEnvironmentRecord()||selectedEnvironmentOverview()||{};try{await runJobsNow(current.id,current.name);}catch(error){setMessage(error.message,"error");}return;}const editRecipientButton=event.target.closest("[data-edit-recipient]");if(editRecipientButton){state.editingRecipientId=editRecipientButton.getAttribute("data-edit-recipient");render();return;}const deleteRecipientButton=event.target.closest("[data-delete-recipient]");if(deleteRecipientButton){try{await deleteRecipient(deleteRecipientButton.getAttribute("data-delete-recipient"));}catch(error){setMessage(error.message,"error");}return;}const resetRecipientButton=event.target.closest("[data-reset-recipient]");if(resetRecipientButton){state.editingRecipientId=null;render();return;}const productTabButton=event.target.closest("[data-product-tab]");if(productTabButton){state.activeProductTab=productTabButton.getAttribute("data-product-tab");persistState();render();return;}const closeModalButton=event.target.closest("[data-close-modal]");if(closeModalButton||event.target===refs.environmentModalClose){closeEnvironmentModal();}});
document.addEventListener("submit",async function(event){if(event.target&&event.target.id==="environment-form"){event.preventDefault();try{await saveEnvironment(false);}catch(error){setMessage(error.message,"error");}return;}if(event.target&&event.target.id==="notification-settings-form"){event.preventDefault();try{await saveNotificationSettings(event.target);}catch(error){setMessage(error.message,"error");}return;}if(event.target&&event.target.id==="notification-test-form"){event.preventDefault();try{await sendNotificationTest(event.target);}catch(error){setMessage(error.message,"error");}return;}if(event.target&&event.target.id==="recipient-form"){event.preventDefault();try{await saveRecipient(event.target);}catch(error){setMessage(error.message,"error");}}});
document.addEventListener("change",function(event){if(event.target===refs.contextSwitcher){changeContext(refs.contextSwitcher.value);return;}if(event.target&&(event.target.name==="environmentType"||event.target.name==="serverSshMode"||event.target.name==="collectionEnabled"))syncEnvironmentFormDisplay();});
refs.environmentModalBackdrop.addEventListener("click",function(event){if(event.target===refs.environmentModalBackdrop)closeEnvironmentModal();});
document.addEventListener("keydown",function(event){if(event.key==="Escape"&&state.environmentModalOpen)closeEnvironmentModal();});
loadStoredState();render();loadAllData(false);
